/**
 * Menu Module Zod Schemas
 *
 * Validation schemas for all Menu module inputs/outputs.
 * Follows the validation rules defined in CODING_STANDARDS.md.
 *
 * @module modules/menu/schema
 *
 * @example
 * ```typescript
 * import {
 *   createMenuSchema,
 *   createProductSchema,
 *   updateCategorySchema,
 * } from '@/modules/menu/menu.schema';
 *
 * // Validate menu input
 * const validatedData = createMenuSchema.parse(req.body);
 * ```
 */

import { z } from 'zod';

// -----------------------------------------------------------------------------
// Constants
// -----------------------------------------------------------------------------

/**
 * Default limits for menu module
 */
const LIMITS = {
  name: { min: 1, max: 100 },
  slug: { min: 1, max: 100 },
  description: { max: 2000 },
  shortDescription: { max: 100 },
  customCss: { max: 50000 },
  tags: { max: 20 },
  gallery: { max: 10 },
  price: { min: 0, max: 999999.99 },
  sortOrder: { min: 0, max: 10000 },
  spicyLevel: { min: 1, max: 5 },
  preparationTime: { min: 1, max: 1440 }, // max 24 hours
  maxQuantity: { min: 1, max: 100 },
} as const;

/**
 * Color validation regex (hex color)
 */
const HEX_COLOR_REGEX = /^#([A-Fa-f0-9]{6}|[A-Fa-f0-9]{3})$/;

/**
 * Slug validation regex
 */
const SLUG_REGEX = /^[a-z0-9]+(?:-[a-z0-9]+)*$/;

// -----------------------------------------------------------------------------
// Base Schemas
// -----------------------------------------------------------------------------

/**
 * Name schema for menu entities
 */
export const nameSchema = z
  .string()
  .trim()
  .min(LIMITS.name.min, 'Name is required')
  .max(LIMITS.name.max, `Name must be at most ${LIMITS.name.max} characters`);

/**
 * Slug schema
 */
export const slugSchema = z
  .string()
  .trim()
  .toLowerCase()
  .min(LIMITS.slug.min, 'Slug is required')
  .max(LIMITS.slug.max, `Slug must be at most ${LIMITS.slug.max} characters`)
  .regex(SLUG_REGEX, 'Slug must contain only lowercase letters, numbers, and hyphens');

/**
 * Optional slug schema
 */
export const optionalSlugSchema = slugSchema.optional();

/**
 * Description schema
 */
export const descriptionSchema = z
  .string()
  .trim()
  .max(LIMITS.description.max, `Description must be at most ${LIMITS.description.max} characters`)
  .optional()
  .nullable();

/**
 * Short description schema
 */
export const shortDescriptionSchema = z
  .string()
  .trim()
  .max(LIMITS.shortDescription.max, `Short description must be at most ${LIMITS.shortDescription.max} characters`)
  .optional()
  .nullable();

/**
 * Price schema
 */
export const priceSchema = z
  .union([z.string(), z.number()])
  .transform((val) => (typeof val === 'string' ? parseFloat(val) : val))
  .refine((val) => !isNaN(val), 'Price must be a valid number')
  .refine((val) => val >= LIMITS.price.min, `Price must be at least ${LIMITS.price.min}`)
  .refine((val) => val <= LIMITS.price.max, `Price must be at most ${LIMITS.price.max}`);

/**
 * Optional price schema
 */
export const optionalPriceSchema = z
  .union([z.string(), z.number()])
  .transform((val) => (typeof val === 'string' ? parseFloat(val) : val))
  .refine((val) => !isNaN(val), 'Price must be a valid number')
  .refine((val) => val >= LIMITS.price.min, `Price must be at least ${LIMITS.price.min}`)
  .refine((val) => val <= LIMITS.price.max, `Price must be at most ${LIMITS.price.max}`)
  .optional();

/**
 * Sort order schema
 */
export const sortOrderSchema = z
  .number()
  .int()
  .min(LIMITS.sortOrder.min)
  .max(LIMITS.sortOrder.max)
  .optional()
  .default(0);

/**
 * CUID schema
 */
export const cuidSchema = z.string().cuid('Invalid ID format');

/**
 * Optional CUID schema
 */
export const optionalCuidSchema = z.string().cuid('Invalid ID format').optional().nullable();

/**
 * URL schema
 */
export const urlSchema = z.string().url('Invalid URL format').optional().nullable();

/**
 * Hex color schema
 */
export const hexColorSchema = z
  .string()
  .regex(HEX_COLOR_REGEX, 'Invalid hex color format (e.g., #FF5733)')
  .optional();

/**
 * Tags array schema
 */
export const tagsSchema = z
  .array(z.string().trim().min(1).max(50))
  .max(LIMITS.tags.max, `Maximum ${LIMITS.tags.max} tags allowed`)
  .optional()
  .default([]);

/**
 * Gallery array schema
 */
export const gallerySchema = z
  .array(z.string().url('Invalid image URL'))
  .max(LIMITS.gallery.max, `Maximum ${LIMITS.gallery.max} gallery images allowed`)
  .optional()
  .default([]);

// -----------------------------------------------------------------------------
// Menu Settings Schema
// -----------------------------------------------------------------------------

/**
 * Menu settings schema
 */
export const menuSettingsSchema = z
  .object({
    showImages: z.boolean().optional().default(true),
    showPrices: z.boolean().optional().default(true),
    showDescriptions: z.boolean().optional().default(true),
    showAllergens: z.boolean().optional().default(true),
    showNutritionInfo: z.boolean().optional().default(false),
    enableOrdering: z.boolean().optional().default(false),
    footerText: z.string().max(500).optional(),
    socialLinks: z.record(z.string().url()).optional().default({}),
  })
  .optional()
  .default({});

/**
 * Inferred type from menu settings schema
 */
export type MenuSettingsInput = z.infer<typeof menuSettingsSchema>;

// -----------------------------------------------------------------------------
// Theme Settings Schema
// -----------------------------------------------------------------------------

/**
 * Theme settings schema
 */
export const themeSettingsSchema = z
  .object({
    borderRadius: z.number().int().min(0).max(50).optional(),
    cardShadow: z.enum(['none', 'sm', 'md', 'lg']).optional(),
    headerStyle: z.enum(['fixed', 'sticky', 'static']).optional(),
    categoryLayout: z.enum(['grid', 'list', 'horizontal']).optional(),
    productCardStyle: z.enum(['minimal', 'detailed', 'image-focused']).optional(),
    enableAnimations: z.boolean().optional(),
    cssVariables: z.record(z.string()).optional(),
  })
  .optional()
  .default({});

/**
 * Inferred type from theme settings schema
 */
export type ThemeSettingsInput = z.infer<typeof themeSettingsSchema>;

// -----------------------------------------------------------------------------
// Menu Schemas
// -----------------------------------------------------------------------------

/**
 * Create menu schema
 */
export const createMenuSchema = z.object({
  name: nameSchema,
  slug: optionalSlugSchema,
  description: descriptionSchema,
  branchId: optionalCuidSchema,
  themeId: optionalCuidSchema,
  isDefault: z.boolean().optional().default(false),
  settings: menuSettingsSchema,
  sortOrder: sortOrderSchema,
});

/**
 * Inferred type from create menu schema
 */
export type CreateMenuInput = z.infer<typeof createMenuSchema>;

/**
 * Update menu schema
 */
export const updateMenuSchema = z.object({
  name: nameSchema.optional(),
  slug: slugSchema.optional(),
  description: descriptionSchema,
  branchId: optionalCuidSchema,
  themeId: optionalCuidSchema,
  isDefault: z.boolean().optional(),
  settings: menuSettingsSchema,
  sortOrder: sortOrderSchema.optional(),
});

/**
 * Inferred type from update menu schema
 */
export type UpdateMenuInput = z.infer<typeof updateMenuSchema>;

/**
 * Publish menu schema
 */
export const publishMenuSchema = z.object({
  generateQrCode: z.boolean().optional().default(true),
});

/**
 * Inferred type from publish menu schema
 */
export type PublishMenuInput = z.infer<typeof publishMenuSchema>;

/**
 * List menus query schema
 */
export const listMenusQuerySchema = z.object({
  isPublished: z
    .string()
    .transform((val) => val === 'true')
    .optional(),
  branchId: optionalCuidSchema,
  search: z.string().trim().max(100).optional(),
  page: z.coerce.number().int().positive().optional().default(1),
  perPage: z.coerce.number().int().positive().max(100).optional().default(20),
  sortBy: z.enum(['name', 'createdAt', 'updatedAt', 'sortOrder']).optional().default('sortOrder'),
  sortOrder: z.enum(['asc', 'desc']).optional().default('asc'),
});

/**
 * Inferred type from list menus query schema
 */
export type ListMenusQueryInput = z.infer<typeof listMenusQuerySchema>;

// -----------------------------------------------------------------------------
// Category Schemas
// -----------------------------------------------------------------------------

/**
 * Create category schema
 */
export const createCategorySchema = z.object({
  menuId: cuidSchema,
  parentId: optionalCuidSchema,
  name: nameSchema,
  slug: optionalSlugSchema,
  description: descriptionSchema,
  image: urlSchema,
  isActive: z.boolean().optional().default(true),
  sortOrder: sortOrderSchema,
});

/**
 * Inferred type from create category schema
 */
export type CreateCategoryInput = z.infer<typeof createCategorySchema>;

/**
 * Update category schema
 */
export const updateCategorySchema = z.object({
  parentId: optionalCuidSchema,
  name: nameSchema.optional(),
  slug: slugSchema.optional(),
  description: descriptionSchema,
  image: urlSchema,
  isActive: z.boolean().optional(),
  sortOrder: sortOrderSchema.optional(),
});

/**
 * Inferred type from update category schema
 */
export type UpdateCategoryInput = z.infer<typeof updateCategorySchema>;

/**
 * Reorder categories schema
 */
export const reorderCategoriesSchema = z.object({
  menuId: cuidSchema,
  items: z
    .array(
      z.object({
        id: cuidSchema,
        sortOrder: z.number().int().min(0),
      })
    )
    .min(1, 'At least one category is required'),
});

/**
 * Inferred type from reorder categories schema
 */
export type ReorderCategoriesInput = z.infer<typeof reorderCategoriesSchema>;

/**
 * List categories query schema
 */
export const listCategoriesQuerySchema = z.object({
  menuId: optionalCuidSchema,
  parentId: z.string().optional().transform((val) => (val === 'null' ? null : val)),
  isActive: z
    .string()
    .transform((val) => val === 'true')
    .optional(),
  includeProducts: z
    .string()
    .transform((val) => val === 'true')
    .optional(),
  search: z.string().trim().max(100).optional(),
  page: z.coerce.number().int().positive().optional().default(1),
  perPage: z.coerce.number().int().positive().max(100).optional().default(50),
});

/**
 * Inferred type from list categories query schema
 */
export type ListCategoriesQueryInput = z.infer<typeof listCategoriesQuerySchema>;

// -----------------------------------------------------------------------------
// Product Schemas
// -----------------------------------------------------------------------------

/**
 * Create variant schema (nested in product)
 */
export const createVariantNestedSchema = z.object({
  name: nameSchema,
  price: priceSchema,
  isDefault: z.boolean().optional().default(false),
  isAvailable: z.boolean().optional().default(true),
  sortOrder: sortOrderSchema,
});

/**
 * Create modifier schema (nested in product)
 */
export const createModifierNestedSchema = z.object({
  name: nameSchema,
  price: priceSchema,
  isDefault: z.boolean().optional().default(false),
  isRequired: z.boolean().optional().default(false),
  maxQuantity: z.number().int().min(LIMITS.maxQuantity.min).max(LIMITS.maxQuantity.max).optional().default(1),
  sortOrder: sortOrderSchema,
});

/**
 * Create nutrition info schema (nested in product)
 */
export const createNutritionInfoSchema = z.object({
  calories: z.number().int().min(0).max(10000).optional(),
  protein: z.number().min(0).max(1000).optional(),
  carbohydrates: z.number().min(0).max(1000).optional(),
  fat: z.number().min(0).max(1000).optional(),
  fiber: z.number().min(0).max(1000).optional(),
  sodium: z.number().min(0).max(100000).optional(),
  sugar: z.number().min(0).max(1000).optional(),
  servingSize: z.string().max(50).optional(),
  servingUnit: z.string().max(20).optional(),
});

/**
 * Inferred type from create nutrition info schema
 */
export type CreateNutritionInfoInput = z.infer<typeof createNutritionInfoSchema>;

/**
 * Create product schema
 */
export const createProductSchema = z.object({
  categoryId: cuidSchema,
  name: nameSchema,
  slug: optionalSlugSchema,
  description: descriptionSchema,
  shortDescription: shortDescriptionSchema,
  basePrice: priceSchema,
  currency: z.string().length(3).toUpperCase().optional().default('TRY'),
  image: urlSchema,
  gallery: gallerySchema,
  isActive: z.boolean().optional().default(true),
  isAvailable: z.boolean().optional().default(true),
  isFeatured: z.boolean().optional().default(false),
  isChefRecommended: z.boolean().optional().default(false),
  preparationTime: z.number().int().min(LIMITS.preparationTime.min).max(LIMITS.preparationTime.max).optional().nullable(),
  calories: z.number().int().min(0).max(10000).optional().nullable(),
  spicyLevel: z.number().int().min(LIMITS.spicyLevel.min).max(LIMITS.spicyLevel.max).optional().nullable(),
  tags: tagsSchema,
  sortOrder: sortOrderSchema,
  allergenIds: z.array(cuidSchema).optional().default([]),
  variants: z.array(createVariantNestedSchema).optional().default([]),
  modifiers: z.array(createModifierNestedSchema).optional().default([]),
  nutritionInfo: createNutritionInfoSchema.optional(),
});

/**
 * Inferred type from create product schema
 */
export type CreateProductInput = z.infer<typeof createProductSchema>;

/**
 * Update product schema
 */
export const updateProductSchema = z.object({
  categoryId: cuidSchema.optional(),
  name: nameSchema.optional(),
  slug: slugSchema.optional(),
  description: descriptionSchema,
  shortDescription: shortDescriptionSchema,
  basePrice: optionalPriceSchema,
  currency: z.string().length(3).toUpperCase().optional(),
  image: urlSchema,
  gallery: gallerySchema,
  isActive: z.boolean().optional(),
  isAvailable: z.boolean().optional(),
  isFeatured: z.boolean().optional(),
  isChefRecommended: z.boolean().optional(),
  preparationTime: z.number().int().min(LIMITS.preparationTime.min).max(LIMITS.preparationTime.max).optional().nullable(),
  calories: z.number().int().min(0).max(10000).optional().nullable(),
  spicyLevel: z.number().int().min(LIMITS.spicyLevel.min).max(LIMITS.spicyLevel.max).optional().nullable(),
  tags: tagsSchema,
  sortOrder: sortOrderSchema.optional(),
  allergenIds: z.array(cuidSchema).optional(),
});

/**
 * Inferred type from update product schema
 */
export type UpdateProductInput = z.infer<typeof updateProductSchema>;

/**
 * Update product availability schema
 */
export const updateAvailabilitySchema = z.object({
  isAvailable: z.boolean(),
});

/**
 * Inferred type from update availability schema
 */
export type UpdateAvailabilityInput = z.infer<typeof updateAvailabilitySchema>;

/**
 * List products query schema
 */
export const listProductsQuerySchema = z.object({
  categoryId: optionalCuidSchema,
  menuId: optionalCuidSchema,
  isActive: z
    .string()
    .transform((val) => val === 'true')
    .optional(),
  isAvailable: z
    .string()
    .transform((val) => val === 'true')
    .optional(),
  isFeatured: z
    .string()
    .transform((val) => val === 'true')
    .optional(),
  allergenId: optionalCuidSchema,
  search: z.string().trim().max(100).optional(),
  tags: z
    .string()
    .transform((val) => val.split(',').map((t) => t.trim()))
    .optional(),
  include: z
    .string()
    .transform((val) => val.split(',') as Array<'category' | 'variants' | 'modifiers' | 'allergens' | 'nutritionInfo'>)
    .optional(),
  page: z.coerce.number().int().positive().optional().default(1),
  perPage: z.coerce.number().int().positive().max(100).optional().default(20),
  sortBy: z.enum(['name', 'basePrice', 'createdAt', 'sortOrder']).optional().default('sortOrder'),
  sortOrder: z.enum(['asc', 'desc']).optional().default('asc'),
});

/**
 * Inferred type from list products query schema
 */
export type ListProductsQueryInput = z.infer<typeof listProductsQuerySchema>;

// -----------------------------------------------------------------------------
// Variant Schemas
// -----------------------------------------------------------------------------

/**
 * Create variant schema (standalone)
 */
export const createVariantSchema = z.object({
  productId: cuidSchema,
  name: nameSchema,
  price: priceSchema,
  isDefault: z.boolean().optional().default(false),
  isAvailable: z.boolean().optional().default(true),
  sortOrder: sortOrderSchema,
});

/**
 * Inferred type from create variant schema
 */
export type CreateVariantInput = z.infer<typeof createVariantSchema>;

/**
 * Update variant schema
 */
export const updateVariantSchema = z.object({
  name: nameSchema.optional(),
  price: optionalPriceSchema,
  isDefault: z.boolean().optional(),
  isAvailable: z.boolean().optional(),
  sortOrder: sortOrderSchema.optional(),
});

/**
 * Inferred type from update variant schema
 */
export type UpdateVariantInput = z.infer<typeof updateVariantSchema>;

// -----------------------------------------------------------------------------
// Modifier Schemas
// -----------------------------------------------------------------------------

/**
 * Create modifier schema (standalone)
 */
export const createModifierSchema = z.object({
  productId: cuidSchema,
  name: nameSchema,
  price: priceSchema,
  isDefault: z.boolean().optional().default(false),
  isRequired: z.boolean().optional().default(false),
  maxQuantity: z.number().int().min(LIMITS.maxQuantity.min).max(LIMITS.maxQuantity.max).optional().default(1),
  sortOrder: sortOrderSchema,
});

/**
 * Inferred type from create modifier schema
 */
export type CreateModifierInput = z.infer<typeof createModifierSchema>;

/**
 * Update modifier schema
 */
export const updateModifierSchema = z.object({
  name: nameSchema.optional(),
  price: optionalPriceSchema,
  isDefault: z.boolean().optional(),
  isRequired: z.boolean().optional(),
  maxQuantity: z.number().int().min(LIMITS.maxQuantity.min).max(LIMITS.maxQuantity.max).optional(),
  sortOrder: sortOrderSchema.optional(),
});

/**
 * Inferred type from update modifier schema
 */
export type UpdateModifierInput = z.infer<typeof updateModifierSchema>;

// -----------------------------------------------------------------------------
// Theme Schemas
// -----------------------------------------------------------------------------

/**
 * Create theme schema
 */
export const createThemeSchema = z.object({
  name: nameSchema,
  slug: optionalSlugSchema,
  description: descriptionSchema,
  primaryColor: hexColorSchema.default('#3B82F6'),
  secondaryColor: hexColorSchema.default('#10B981'),
  backgroundColor: hexColorSchema.default('#FFFFFF'),
  textColor: hexColorSchema.default('#1F2937'),
  fontFamily: z.string().max(100).optional().default('Inter'),
  logoPosition: z.enum(['left', 'center', 'right']).optional().default('left'),
  customCss: z.string().max(LIMITS.customCss.max).optional().nullable(),
  settings: themeSettingsSchema,
  isDefault: z.boolean().optional().default(false),
  isActive: z.boolean().optional().default(true),
});

/**
 * Inferred type from create theme schema
 */
export type CreateThemeInput = z.infer<typeof createThemeSchema>;

/**
 * Update theme schema
 */
export const updateThemeSchema = z.object({
  name: nameSchema.optional(),
  slug: slugSchema.optional(),
  description: descriptionSchema,
  primaryColor: hexColorSchema,
  secondaryColor: hexColorSchema,
  backgroundColor: hexColorSchema,
  textColor: hexColorSchema,
  fontFamily: z.string().max(100).optional(),
  logoPosition: z.enum(['left', 'center', 'right']).optional(),
  customCss: z.string().max(LIMITS.customCss.max).optional().nullable(),
  settings: themeSettingsSchema,
  isDefault: z.boolean().optional(),
  isActive: z.boolean().optional(),
});

/**
 * Inferred type from update theme schema
 */
export type UpdateThemeInput = z.infer<typeof updateThemeSchema>;

/**
 * List themes query schema
 */
export const listThemesQuerySchema = z.object({
  isActive: z
    .string()
    .transform((val) => val === 'true')
    .optional(),
  search: z.string().trim().max(100).optional(),
  page: z.coerce.number().int().positive().optional().default(1),
  perPage: z.coerce.number().int().positive().max(100).optional().default(20),
});

/**
 * Inferred type from list themes query schema
 */
export type ListThemesQueryInput = z.infer<typeof listThemesQuerySchema>;

// -----------------------------------------------------------------------------
// Nutrition Info Schema (standalone update)
// -----------------------------------------------------------------------------

/**
 * Update nutrition info schema
 */
export const updateNutritionInfoSchema = createNutritionInfoSchema;

/**
 * Inferred type from update nutrition info schema
 */
export type UpdateNutritionInfoInput = z.infer<typeof updateNutritionInfoSchema>;

// -----------------------------------------------------------------------------
// Response Schemas (for documentation)
// -----------------------------------------------------------------------------

/**
 * Menu response schema
 */
export const menuResponseSchema = z.object({
  id: cuidSchema,
  organizationId: cuidSchema,
  branchId: z.string().nullable(),
  name: z.string(),
  slug: z.string(),
  description: z.string().nullable(),
  isPublished: z.boolean(),
  publishedAt: z.date().nullable(),
  isDefault: z.boolean(),
  themeId: z.string().nullable(),
  settings: menuSettingsSchema,
  sortOrder: z.number(),
  createdAt: z.date(),
  updatedAt: z.date(),
  categoryCount: z.number().optional(),
  productCount: z.number().optional(),
});

/**
 * Category response schema
 */
export const categoryResponseSchema = z.object({
  id: cuidSchema,
  organizationId: cuidSchema,
  menuId: cuidSchema,
  parentId: z.string().nullable(),
  name: z.string(),
  slug: z.string(),
  description: z.string().nullable(),
  image: z.string().nullable(),
  isActive: z.boolean(),
  sortOrder: z.number(),
  createdAt: z.date(),
  updatedAt: z.date(),
});

/**
 * Product response schema
 */
export const productResponseSchema = z.object({
  id: cuidSchema,
  organizationId: cuidSchema,
  categoryId: cuidSchema,
  name: z.string(),
  slug: z.string(),
  description: z.string().nullable(),
  shortDescription: z.string().nullable(),
  basePrice: z.union([z.string(), z.number()]),
  currency: z.string(),
  image: z.string().nullable(),
  gallery: z.array(z.string()),
  isActive: z.boolean(),
  isAvailable: z.boolean(),
  isFeatured: z.boolean(),
  isChefRecommended: z.boolean(),
  preparationTime: z.number().nullable(),
  calories: z.number().nullable(),
  spicyLevel: z.number().nullable(),
  tags: z.array(z.string()),
  sortOrder: z.number(),
  createdAt: z.date(),
  updatedAt: z.date(),
});

// -----------------------------------------------------------------------------
// Utility Functions
// -----------------------------------------------------------------------------

/**
 * Generates a URL-friendly slug from a string
 *
 * @param text - Text to convert to slug
 * @returns URL-friendly slug
 *
 * @example
 * ```typescript
 * const slug = generateSlug('Kahvaltı Menüsü');
 * // Returns: 'kahvalti-menusu'
 * ```
 */
export function generateSlug(text: string): string {
  return text
    .toLowerCase()
    .trim()
    // Turkish character replacements
    .replace(/ğ/g, 'g')
    .replace(/ü/g, 'u')
    .replace(/ş/g, 's')
    .replace(/ı/g, 'i')
    .replace(/ö/g, 'o')
    .replace(/ç/g, 'c')
    // General transformations
    .replace(/[^\w\s-]/g, '') // Remove special characters
    .replace(/[\s_-]+/g, '-') // Replace spaces and underscores with hyphens
    .replace(/^-+|-+$/g, ''); // Remove leading/trailing hyphens
}

/**
 * Validates and parses price input
 *
 * @param value - Price value (string or number)
 * @returns Parsed price as number
 * @throws ZodError if invalid
 *
 * @example
 * ```typescript
 * const price = parsePrice('25.50');
 * // Returns: 25.5
 * ```
 */
export function parsePrice(value: string | number): number {
  return priceSchema.parse(value);
}

/**
 * Validates hex color format
 *
 * @param color - Color string to validate
 * @returns True if valid hex color
 *
 * @example
 * ```typescript
 * const isValid = isValidHexColor('#FF5733');
 * // Returns: true
 * ```
 */
export function isValidHexColor(color: string): boolean {
  return HEX_COLOR_REGEX.test(color);
}

/**
 * Validates slug format
 *
 * @param slug - Slug string to validate
 * @returns True if valid slug
 *
 * @example
 * ```typescript
 * const isValid = isValidSlug('my-menu-slug');
 * // Returns: true
 * ```
 */
export function isValidSlug(slug: string): boolean {
  return SLUG_REGEX.test(slug);
}
